import { useState, useEffect } from 'react';
import axios from 'axios';

const SlotGrid = () => {
    const [slots, setSlots] = useState([]);
    const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
    const [loading, setLoading] = useState(true);

    const fetchSlots = async () => {
        try {
            setLoading(true);
            const res = await axios.get(`http://localhost:5000/api/slots?date=${selectedDate}`);
            setSlots(res.data);
            setLoading(false);
        } catch (err) {
            console.error('Error fetching slots:', err);
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchSlots();
    }, [selectedDate]);

    const getStatusColor = (status) => {
        switch (status) {
            case 'free': return 'bg-green-100 border-green-500 text-green-700 hover:bg-green-200 cursor-pointer shadow-sm';
            case 'booked': return 'bg-red-100 border-red-500 text-red-700 opacity-75 cursor-not-allowed';
            case 'hold': return 'bg-yellow-100 border-yellow-500 text-yellow-700 opacity-75 cursor-not-allowed';
            default: return 'bg-gray-100 border-gray-300';
        }
    };

    const handleSlotClick = (slot) => {
        if (slot.status === 'free') {
            alert(`Booking ${slot.startTime} - ${slot.endTime} on ${slot.date}`);
            // TODO: Open booking modal
        }
    };

    return (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
            <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
                <h3 className="text-2xl font-bold text-gray-800">Available Slots</h3>
                <input
                    type="date"
                    value={selectedDate}
                    onChange={(e) => setSelectedDate(e.target.value)}
                    className="px-6 py-3 border border-gray-200 rounded-2xl shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-semibold text-gray-700"
                />
            </div>

            {loading ? (
                <div className="flex justify-center items-center py-20">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
                </div>
            ) : slots.length === 0 ? (
                <div className="text-center py-20 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 text-gray-400 italic">
                    No slots available for this date.
                </div>
            ) : (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                    {slots.map((slot) => (
                        <div
                            key={slot._id}
                            onClick={() => handleSlotClick(slot)}
                            className={`p-6 border-2 rounded-2xl transition-all font-bold flex flex-col items-center justify-center text-center gap-2 ${getStatusColor(slot.status)}`}
                        >
                            <span className="text-lg tracking-tight">{slot.startTime} - {slot.endTime}</span>
                            <span className="text-[10px] uppercase tracking-widest opacity-60">
                                {slot.status === 'booked' ? `Booked by ${slot.bookedBy || 'User'}` : slot.status}
                            </span>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default SlotGrid;

import { createContext, useState, useEffect } from 'react';
import { authAPI } from '../api/client';
import apiClient from '../api/client';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(() => {
    try {
      const storedUser = localStorage.getItem('user');
      return storedUser ? JSON.parse(storedUser) : null;
    } catch (error) {
      console.error('Error parsing user from localStorage:', error);
      return null;
    }
  });
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (token) {
      // Logic to verify token or fetch fresh user data could go here
      setLoading(false);
    } else {
      setLoading(false);
    }
  }, [token]);

  const login = async (role, email, password) => {
    try {
      const res = await authAPI.login(email, password, role);

      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      setToken(res.data.token);
      setUser(res.data.user);
      return { success: true, user: res.data.user };
    } catch (error) {
      console.error('Login error:', error.response?.data?.message || error.message);
      return { success: false, message: error.response?.data?.message || 'Login failed' };
    }
  };

  const register = async (name, email, phone, password) => {
    try {
      const res = await authAPI.register(name, email, phone, password);

      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      setToken(res.data.token);
      setUser(res.data.user);
      return { success: true, user: res.data.user };
    } catch (error) {
      console.error('Registration error:', error.response?.data?.message || error.message);
      return { success: false, message: error.response?.data?.message || 'Registration failed' };
    }
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setToken(null);
    setUser(null);
    // Force a hard reload to clear any sensitive state if necessary, 
    // or just rely on navigation to home.
    window.location.href = '/';
  };

  return (
    <AuthContext.Provider value={{ user, token, login, register, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export default AuthContext;

import React, { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { slotsAPI, bookingsAPI } from '../api/client';
import AuthContext from '../context/AuthContext';
import { Calendar, Clock, User, Phone, MapPin, ShieldCheck, ChevronRight, Info, Zap, ArrowLeft } from 'lucide-react';

const BookingPage = () => {
    const { slotId } = useParams();
    const navigate = useNavigate();
    const { user } = useContext(AuthContext);
    const [slot, setSlot] = useState(null);
    const [loading, setLoading] = useState(true);
    const [formData, setFormData] = useState({
        fullName: user?.name || '',
        whatsappNumber: user?.phone || '',
        date: '',
        startTime: '',
        endTime: ''
    });
    const [calculatedPrice, setCalculatedPrice] = useState(500);
    const [error, setError] = useState('');
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        if (formData.startTime && formData.endTime) {
            const [sh, sm] = formData.startTime.split(':').map(Number);
            const [eh, em] = formData.endTime.split(':').map(Number);
            const duration = (eh * 60 + em) - (sh * 60 + sm);
            if (duration > 0) {
                setCalculatedPrice(Math.max(200, Math.ceil((duration / 60) * 500)));
            }
        }
    }, [formData.startTime, formData.endTime]);

    const adjustEndTime = (minutes) => {
        if (!formData.startTime) return;
        const [h, m] = formData.startTime.split(':').map(Number);
        const totalMins = h * 60 + m + minutes;
        const nh = Math.floor(totalMins / 60);
        const nm = totalMins % 60;
        // Cap at 23:59
        const cappedH = Math.min(23, nh);
        const cappedM = nh > 23 ? 59 : nm;
        const newEndTime = `${cappedH.toString().padStart(2, '0')}:${cappedM.toString().padStart(2, '0')}`;
        setFormData(prev => ({ ...prev, endTime: newEndTime }));
    };

    useEffect(() => {
        const fetchSlot = async () => {
            if (!slotId || slotId === 'custom') {
                setFormData(prev => ({
                    ...prev,
                    date: new Date().toISOString().split('T')[0],
                    startTime: '10:00',
                    endTime: '11:00'
                }));
                setLoading(false);
                return;
            }
            try {
                const res = await slotsAPI.getById(slotId);
                const s = res.data.slot || res.data;
                setSlot(s);
                // Sync formData with slot data
                setFormData(prev => ({
                    ...prev,
                    date: s.date ? new Date(s.date).toISOString().split('T')[0] : '',
                    startTime: s.startTime || '',
                    endTime: s.endTime || ''
                }));
                setLoading(false);
            } catch (err) {
                console.error('Error fetching slot:', err);
                setError('Failed to load slot details.');
                setLoading(false);
            }
        };
        fetchSlot();
    }, [slotId]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!formData.fullName || !formData.whatsappNumber || !formData.date || !formData.startTime || !formData.endTime) {
            setError('Operational Protocol Violation: All deployment specifications (Name, WhatsApp, Date, Start, and End) must be finalized.');
            return;
        }

        if (formData.whatsappNumber.length !== 10) {
            setError('Invalid Pulse. Please enter a valid 10-digit number.');
            return;
        }

        setSubmitting(true);
        try {
            const apiPayload = {
                userName: formData.fullName,
                userPhone: formData.whatsappNumber,
                date: formData.date,
                startTime: formData.startTime,
                endTime: formData.endTime,
                turfLocation: 'The Turf, Miyapur',
                amount: calculatedPrice,
                userId: user?.id
            };

            if (slotId && slotId !== 'custom') {
                apiPayload.slotId = slotId;
            }

            const res = await bookingsAPI.create(apiPayload);

            navigate(`/payment/${res.data.booking._id}`);
        } catch (err) {
            console.error('Booking error:', err);
            const serverMessage = err.response?.data?.message;
            const targetUrl = process.env.REACT_APP_API_URL || 'localhost (Spec Violation)';
            setError(serverMessage || `Synchronization Error. Target [${targetUrl}] may be unstable.`);
            setSubmitting(false);
        }
    };

    const formatTime12h = (time24) => {
        if (!time24) return '';
        const [hours, minutes] = time24.split(':');
        const h = parseInt(hours);
        const ampm = h >= 12 ? 'PM' : 'AM';
        const h12 = h % 12 || 12;
        return `${h12}:${minutes} ${ampm}`;
    };

    if (loading) return (
        <div className="min-h-screen bg-[#F8FAFC] flex flex-col items-center justify-center p-6">
            <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin mb-4"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-gray-400">Initializing Reservation Protocol...</p>
        </div>
    );

    const courtFee = Math.round(calculatedPrice * 0.8);
    const convenienceFee = calculatedPrice - courtFee;

    return (
        <div className="min-h-screen bg-[#F8FAFC] pb-24">
            {/* Minimal Header for Flow */}
            <div className="bg-white border-b border-gray-100 h-20 md:h-24 flex items-center px-4 md:px-6 sticky top-0 z-50">
                <div className="max-w-7xl mx-auto w-full flex items-center justify-between">
                    <button onClick={() => navigate('/')} className="flex items-center gap-2 md:gap-3 text-gray-400 hover:text-emerald-600 transition-all group">
                        <div className="bg-gray-50 p-2 md:p-2.5 rounded-xl group-hover:bg-emerald-50 transition-colors">
                            <ArrowLeft size={18} />
                        </div>
                        <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.2em]">Abort Reservation</span>
                    </button>
                    <div className="flex items-center gap-3 md:gap-4">
                        <div className="h-2 w-2 bg-emerald-500 rounded-full animate-pulse shadow-lg shadow-emerald-500/50"></div>
                        <span className="text-[8px] md:text-[9px] font-black text-gray-400 uppercase tracking-[0.3em]">Live Node Sync</span>
                    </div>
                </div>
            </div>

            <div className="max-w-6xl mx-auto px-4 md:px-6 py-10 md:py-16">
                <div className="grid lg:grid-cols-2 gap-10 md:gap-16 items-start">

                    {/* Left Column: Summary & Verification */}
                    <div className="space-y-8 md:space-y-10">
                        <div className="flex flex-col gap-3 md:gap-4">
                            <div className="bg-emerald-50 text-emerald-600 px-4 py-1.5 rounded-full text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] w-fit">
                                Milestone: Slot Reservation
                            </div>
                            <h1 className="text-3xl md:text-5xl font-black text-gray-900 tracking-tighter uppercase leading-none">
                                Allocation <span className="text-emerald-600">Details</span>
                            </h1>
                            <p className="text-xs md:text-sm text-gray-500 font-medium leading-relaxed max-w-sm">
                                System ready for slot assignment. Verify the temporal window and location identifiers before proceeding.
                            </p>
                        </div>

                        <div className="space-y-4">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-xl shadow-emerald-900/[0.02] flex flex-col gap-4 transition-transform hover:scale-[1.02]">
                                    <div className="bg-emerald-100 p-3 rounded-2xl text-emerald-600 w-fit">
                                        <Calendar size={24} />
                                    </div>
                                    <div>
                                        <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Target Date</p>
                                        <p className="font-black text-gray-900 text-lg uppercase tracking-tight">
                                            {formData.date ? new Date(formData.date).toLocaleDateString('en-US', { day: 'numeric', month: 'long', year: 'numeric' }) : 'SELECT DATE'}
                                        </p>
                                    </div>
                                </div>

                                <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-xl shadow-emerald-900/[0.02] flex flex-col gap-4 transition-transform hover:scale-[1.02]">
                                    <div className="bg-emerald-100 p-3 rounded-2xl text-emerald-600 w-fit">
                                        <Clock size={24} />
                                    </div>
                                    <div>
                                        <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Temporal Window</p>
                                        <div className="flex items-center justify-between">
                                            <p className="font-black text-gray-900 text-lg uppercase tracking-tight leading-none">
                                                {formatTime12h(formData.startTime)} – {formatTime12h(formData.endTime)}
                                            </p>
                                            {formData.startTime && formData.endTime && (
                                                <span className="text-[8px] font-black bg-emerald-100 text-emerald-700 px-2 py-1 rounded-md uppercase">
                                                    {(() => {
                                                        const [sh, sm] = formData.startTime.split(':').map(Number);
                                                        const [eh, em] = formData.endTime.split(':').map(Number);
                                                        const mins = (eh * 60 + em) - (sh * 60 + sm);
                                                        return mins > 0 ? `${mins} MINS` : 'INV';
                                                    })()}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-xl shadow-emerald-900/[0.03] flex items-center gap-6">
                                <div className="bg-emerald-500/10 p-5 rounded-3xl text-emerald-600 border border-emerald-500/20">
                                    <Zap size={28} className="fill-emerald-600/10" />
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Total Fee (Min-wise)</p>
                                    <p className="text-3xl font-black text-gray-900 tracking-tighter leading-none">
                                        ₹{calculatedPrice.toLocaleString()}
                                    </p>
                                </div>
                            </div>

                            <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-xl shadow-emerald-900/[0.02] flex items-center justify-between transition-transform hover:scale-[1.01]">
                                <div className="flex items-center gap-6">
                                    <div className="bg-emerald-100 p-4 rounded-3xl text-emerald-600 shadow-inner">
                                        <MapPin size={28} />
                                    </div>
                                    <div>
                                        <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Venue Cluster</p>
                                        <p className="font-black text-gray-900 text-xl uppercase tracking-tighter">The Turf, Miyapur</p>
                                        <p className="text-[10px] text-emerald-600 font-black uppercase tracking-widest mt-0.5">Arena One · Premier Surface</p>
                                    </div>
                                </div>
                                <div className="hidden md:block">
                                    <Zap size={24} className="text-gray-100 fill-gray-100" />
                                </div>
                            </div>
                        </div>

                        <div className="bg-[#1e293b] p-10 rounded-[3rem] shadow-2xl shadow-emerald-950/20 text-white relative overflow-hidden">
                            <div className="absolute top-0 right-0 p-6 opacity-10">
                                <ShieldCheck size={140} className="text-emerald-400" />
                            </div>
                            <div className="flex items-center gap-3 text-emerald-400 font-black mb-4 text-[10px] uppercase tracking-[0.3em] relative z-10">
                                <Zap size={18} className="fill-emerald-400" /> Arena Protocol v1.0
                            </div>
                            <h3 className="text-xl font-black uppercase tracking-tight mb-4 relative z-10">Encryption Active</h3>
                            <p className="text-sm text-gray-400 leading-relaxed font-medium relative z-10">
                                All reservation data is handled through our high-precision matching engine. Confirmation identifiers will be transmitted to your terminal via encrypted WhatsApp protocol.
                            </p>
                        </div>
                    </div>

                    {/* Right Column: Reservation Form */}
                    <div className="bg-white rounded-[2.5rem] md:rounded-[3.5rem] shadow-2xl shadow-emerald-950/5 p-8 md:p-12 border border-blue-50/20 relative">
                        <div className="mb-8 md:mb-12 flex items-center justify-between">
                            <div>
                                <h2 className="text-2xl md:text-3xl font-black text-gray-900 tracking-tighter uppercase leading-none">Identity</h2>
                                <p className="text-[9px] md:text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mt-2">Operator Information</p>
                            </div>
                            <div className="h-12 w-12 md:h-14 md:w-14 bg-gray-50 rounded-2xl flex items-center justify-center text-emerald-600 border border-gray-100">
                                <User size={24} />
                            </div>
                        </div>

                        <form onSubmit={handleSubmit} className="space-y-10">
                            <div className="space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Target Date</label>
                                        <input
                                            type="date"
                                            value={formData.date}
                                            onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                                            className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500/30 focus:bg-white p-6 rounded-[1.5rem] outline-none transition-all font-black text-sm text-gray-900 uppercase tracking-wider"
                                            required
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Time Segment (07:00 AM - 11:00 PM)</label>
                                        <div className="flex flex-col gap-2">
                                            <div className="flex gap-2">
                                                <input
                                                    type="time"
                                                    min="07:00"
                                                    max="23:00"
                                                    value={formData.startTime}
                                                    onChange={(e) => setFormData({ ...formData, startTime: e.target.value })}
                                                    className="w-1/2 bg-gray-50 border-2 border-transparent focus:border-emerald-500/30 focus:bg-white p-4 md:p-6 rounded-xl md:rounded-[1.5rem] outline-none transition-all font-black text-xs md:text-sm text-gray-900 uppercase tracking-wider"
                                                    required
                                                />
                                                <input
                                                    type="time"
                                                    min="07:00"
                                                    max="23:00"
                                                    value={formData.endTime}
                                                    onChange={(e) => setFormData({ ...formData, endTime: e.target.value })}
                                                    className="w-1/2 bg-gray-50 border-2 border-transparent focus:border-emerald-500/30 focus:bg-white p-4 md:p-6 rounded-xl md:rounded-[1.5rem] outline-none transition-all font-black text-xs md:text-sm text-gray-900 uppercase tracking-wider"
                                                    required
                                                />
                                            </div>
                                            <div className="flex gap-2 px-1">
                                                {[60, 90, 120].map(mins => (
                                                    <button
                                                        key={mins}
                                                        type="button"
                                                        onClick={() => adjustEndTime(mins)}
                                                        className="flex-1 py-2 rounded-xl bg-emerald-50 text-emerald-600 text-[8px] font-black uppercase tracking-widest hover:bg-emerald-600 hover:text-white transition-all border border-emerald-100"
                                                    >
                                                        {mins} MINS
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Full Identity</label>
                                    <div className="relative group">
                                        <User className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-300 group-focus-within:text-emerald-500 transition-colors" size={18} />
                                        <input
                                            type="text"
                                            placeholder="RECIPIENT NAME"
                                            value={formData.fullName}
                                            onChange={(e) => setFormData({ ...formData, fullName: e.target.value.toUpperCase() })}
                                            className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500/30 focus:bg-white p-5 md:p-6 pl-14 md:pl-16 rounded-xl md:rounded-[1.5rem] outline-none transition-all font-black text-xs md:text-sm text-gray-900 placeholder:text-gray-200 uppercase tracking-wider"
                                            required
                                        />
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">WhatsApp Comm-Link</label>
                                    <div className="relative group">
                                        <Phone className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-300 group-focus-within:text-emerald-500 transition-colors" size={18} />
                                        <input
                                            type="tel"
                                            maxLength="10"
                                            placeholder="000 000 0000"
                                            value={formData.whatsappNumber}
                                            onChange={(e) => setFormData({ ...formData, whatsappNumber: e.target.value.replace(/\D/g, '') })}
                                            className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500/30 focus:bg-white p-5 md:p-6 pl-14 md:pl-16 rounded-xl md:rounded-[1.5rem] outline-none transition-all font-black text-xs md:text-sm text-gray-900 placeholder:text-gray-200 tracking-[0.15em] md:tracking-[0.2em]"
                                            required
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="bg-gray-950 p-10 rounded-[2.5rem] space-y-6 shadow-2xl shadow-gray-950/20">
                                <div className="flex justify-between items-center">
                                    <span className="text-gray-500 font-black uppercase tracking-[0.2em] text-[9px]">Infrastructure Access</span>
                                    <span className="font-black text-white text-xs tracking-wider">₹{courtFee.toLocaleString()}.00</span>
                                </div>
                                <div className="flex justify-between items-center">
                                    <span className="text-gray-500 font-black uppercase tracking-[0.2em] text-[9px]">System Overhead</span>
                                    <span className="font-black text-white text-xs tracking-wider">₹{convenienceFee.toLocaleString()}.00</span>
                                </div>
                                <div className="pt-6 border-t border-white/5 flex justify-between items-center">
                                    <span className="font-black text-white uppercase tracking-widest text-[10px]">Total Balance Due</span>
                                    <span className="text-4xl font-black text-emerald-400 tracking-tighter">₹{calculatedPrice.toLocaleString()}.00</span>
                                </div>
                            </div>

                            {error && (
                                <div className="bg-red-50/50 border-2 border-red-100/50 p-6 rounded-[1.5rem] flex items-start gap-4 animate-shake">
                                    <div className="bg-red-500 text-white p-1.5 rounded-lg shadow-lg shadow-red-500/30 shrink-0"><Info size={14} /></div>
                                    <p className="text-red-700 text-[10px] font-black uppercase tracking-widest leading-normal">System: {error}</p>
                                </div>
                            )}

                            <div className="pt-2 space-y-6">
                                <button
                                    type="submit"
                                    disabled={submitting}
                                    className="w-full bg-emerald-600 hover:bg-emerald-700 disabled:bg-gray-200 text-white font-black py-7 rounded-[2rem] shadow-2xl shadow-emerald-500/20 hover:shadow-emerald-500/40 transition-all transform hover:-translate-y-1 active:scale-95 text-xs uppercase tracking-[0.3em] flex items-center justify-center gap-4 group overflow-hidden relative"
                                >
                                    {submitting ? (
                                        <>
                                            <div className="w-5 h-5 border-3 border-white/30 border-t-white rounded-full animate-spin"></div>
                                            DEPLOYING RESERVATION...
                                        </>
                                    ) : (
                                        <>
                                            Authorize Payment Phase
                                            <ChevronRight size={18} className="group-hover:translate-x-1 transition-transform" />
                                        </>
                                    )}
                                </button>
                                <div className="text-center px-6">
                                    <p className="text-[8px] text-gray-300 font-bold uppercase tracking-[0.3em] leading-relaxed">
                                        By authorizing, you consent to the <span className="text-emerald-600/60 underline cursor-pointer hover:text-emerald-600 transition-colors">Protocol Agreements</span> and automated system policies.
                                    </p>
                                </div>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BookingPage;

import { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import AuthContext from '../context/AuthContext';
import { Mail, Lock, LogIn, AlertCircle, ChevronRight, ShieldCheck, User } from 'lucide-react';

const Login = () => {
    const { login } = useContext(AuthContext);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const result = await login('user', email, password);

            if (result.success) {
                const userRole = result.user.role;
                if (userRole === 'admin') {
                    navigate('/admin/dashboard');
                } else if (userRole === 'worker') {
                    navigate('/worker/dashboard');
                } else {
                    navigate('/dashboard');
                }
            } else {
                setError(result.message || 'Authentication failed. Please verify your credentials.');
            }
        } catch (err) {
            console.error(err);
            setError('Global synchronization failure. Please verify connection.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-[#F8FAFC] flex items-center justify-center p-6 relative overflow-hidden font-sans">
            {/* Ambient Background Elements */}
            <div className="absolute inset-0 z-0 pointer-events-none opacity-40">
                <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-emerald-100 rounded-full blur-[120px]"></div>
                <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-emerald-50 rounded-full blur-[120px]"></div>
            </div>

            <div className="w-full max-w-xl relative z-10">
                <div className="bg-white/80 backdrop-blur-xl rounded-[3rem] shadow-2xl p-10 md:p-14 border border-white/20">
                    <div className="text-center mb-10">
                        <div className="inline-flex bg-emerald-600 text-white p-5 rounded-[2rem] mb-6 shadow-xl shadow-emerald-200">
                            <LogIn size={40} />
                        </div>
                        <h2 className="text-4xl font-black text-gray-900 tracking-tighter uppercase leading-none">Welcome Back</h2>
                        <p className="text-[10px] font-black text-emerald-600 uppercase tracking-[0.4em] mt-4">Authorized Access Only</p>
                    </div>

                    {error && (
                        <div className="bg-red-50 border border-red-100 p-5 rounded-3xl flex items-start gap-4 mb-8 animate-shake">
                            <AlertCircle size={20} className="text-red-500 shrink-0 mt-0.5" />
                            <p className="text-[11px] font-black text-red-600 leading-relaxed uppercase tracking-tight">{error}</p>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2">Email Address</label>
                            <div className="relative group">
                                <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-600 transition-colors" size={18} />
                                <input
                                    type="email"
                                    required
                                    placeholder="player@theturf.com"
                                    className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500/50 p-4 pl-14 rounded-2xl outline-none transition-all font-bold text-sm text-gray-900 placeholder:text-gray-300"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2">Access Key</label>
                            <div className="relative group">
                                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-600 transition-colors" size={18} />
                                <input
                                    type="password"
                                    required
                                    placeholder="••••••••"
                                    className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500/50 p-4 pl-14 rounded-2xl outline-none transition-all font-bold text-sm text-gray-900 placeholder:text-gray-300"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="pt-4">
                            <button
                                type="submit"
                                disabled={loading}
                                className="w-full bg-gray-900 hover:bg-black text-white py-5 rounded-[2rem] font-black uppercase text-xs tracking-[0.3em] flex items-center justify-center gap-4 transition-all shadow-2xl shadow-gray-200 outline-none hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50"
                            >
                                {loading ? 'Validating...' : (
                                    <>
                                        Initiate Session <ChevronRight size={20} />
                                    </>
                                )}
                            </button>
                        </div>
                    </form>

                    <div className="mt-12 pt-8 border-t border-gray-100 text-center space-y-4">
                        <p className="text-gray-500 text-[11px] font-bold uppercase tracking-widest">
                            New to the roster? <Link to="/register" className="text-emerald-600 hover:text-emerald-800 transition-colors">Apply for Registry</Link>
                        </p>
                        <div className="flex flex-wrap items-center justify-center gap-4 text-[9px] font-black text-gray-300 uppercase tracking-[0.2em]">
                            <Link to="/admin/login" className="hover:text-emerald-600 transition-colors">Admin Portal</Link>
                            <span className="opacity-20">•</span>
                            <Link to="/worker/login" className="hover:text-emerald-600 transition-colors">Worker Terminal</Link>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { slotsAPI } from '../api/client';
import { Calendar, ChevronRight, Zap, MapPin, Plus } from 'lucide-react';

const PublicHome = () => {
    const getISODate = (date = new Date()) => {
        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const day = String(date.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    };

    const [slots, setSlots] = useState([]);
    const [selectedDate, setSelectedDate] = useState(getISODate());
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const [currentImageIndex, setCurrentImageIndex] = useState(0);
    const heroImages = [
        'https://lh3.googleusercontent.com/p/AF1QipNPrYKn27LUcosUUL_CKc_0kJAwvZidmXHu1fQI=w426-h240-k-no',
        'https://lh3.googleusercontent.com/p/AF1QipMsbwyFcmcNneeEsp6NfnXw27Ovyk38W3LqHRk_=w203-h114-k-no',
        'https://lh3.googleusercontent.com/gps-cs-s/AHVAwepkoP29RPlPNGboLneeOgvbhpHEwA99AxCpM55ViIdwNpOmphYvagNoffmNoh8g6xJ52bLQCmpLWMh1MxvnOZixgrwC8qCtHVvW5STmUmO_pWnP3Tem2-ceTSUzPnUxUazvfe1NBw=w203-h152-k-no',
        'https://lh3.googleusercontent.com/p/AF1QipOn7CkSrcWUs8IeOSKZFX0MT1NMp37Evqr1sSPZ=w203-h152-k-no'
    ];

    useEffect(() => {
        const timer = setInterval(() => {
            setCurrentImageIndex((prev) => (prev + 1) % heroImages.length);
        }, 5000);
        return () => clearInterval(timer);
    }, [heroImages.length]);

    useEffect(() => {
        const fetchSlots = async () => {
            try {
                setLoading(true);
                setError(null);
                const res = await slotsAPI.getAll(selectedDate);
                if (Array.isArray(res.data)) setSlots(res.data);
                else setSlots([]);
                setLoading(false);
            } catch (err) {
                console.error('Error fetching slots:', err);
                setError(`Terminal synchronization failure. Attempting to reach: ${process.env.REACT_APP_API_URL || 'localhost'}`);
                setLoading(false);
            }
        };
        fetchSlots();
    }, [selectedDate]);

    const formatTime12h = (time24) => {
        if (!time24) return '';
        const [hours, minutes] = time24.split(':');
        const h = parseInt(hours);
        const ampm = h >= 12 ? 'PM' : 'AM';
        const h12 = h % 12 || 12;
        return `${h12}:${minutes} ${ampm}`;
    };

    const dates = [0, 1, 2, 3, 4, 5, 6].map(days => {
        const d = new Date();
        d.setDate(d.getDate() + days);
        const localDateStr = d.toLocaleDateString('en-CA');
        return {
            dateStr: localDateStr,
            display: d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }),
            label: days === 0 ? "TODAY" : days === 1 ? "TOMORROW" : "AVAILABLE",
            days
        };
    });

    return (
        <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
            {/* HERO SECTION WITH BACKGROUND IMAGE SLIDER */}
            <section className="relative h-[400px] md:h-[480px] w-full flex flex-col items-center justify-center overflow-hidden">
                {heroImages.map((img, idx) => (
                    <div
                        key={idx}
                        className={`absolute inset-0 bg-cover bg-center brightness-[0.4] transition-all duration-1000 ease-in-out transform ${idx === currentImageIndex
                            ? 'opacity-100 scale-100'
                            : 'opacity-0 scale-105 select-none pointer-events-none'
                            }`}
                        style={{ backgroundImage: `url('${img}')` }}
                    ></div>
                ))}

                <div className="relative z-10 text-center space-y-4 px-6 md:px-4">
                    <h1 className="text-4xl md:text-8xl font-black text-white tracking-tighter uppercase leading-none drop-shadow-2xl">
                        Feel Free <span className="text-emerald-400"> Play Better</span>
                    </h1>
                    <p className="text-[10px] md:text-sm font-black text-white/80 uppercase tracking-[0.4em] md:tracking-[1em] mb-8 md:mb-12 drop-shadow-lg">
                        Select your squad. Lock your slot
                    </p>

                    {/* SLIDER DOTS */}
                    <div className="flex justify-center gap-2 md:gap-3">
                        {heroImages.map((_, idx) => (
                            <button
                                key={idx}
                                onClick={() => setCurrentImageIndex(idx)}
                                className={`h-1 md:h-1.5 rounded-full transition-all duration-500 ${idx === currentImageIndex ? 'w-6 md:w-8 bg-emerald-400' : 'w-1.5 md:w-2 bg-white/30'
                                    }`}
                            ></button>
                        ))}
                    </div>
                </div>
            </section>

            {/* MAIN INTERFACE OVERLAPPING HERO */}
            <div className="max-w-7xl mx-auto w-full px-4 md:px-6 -mt-16 md:-mt-32 relative z-20 mb-16 md:mb-32">
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8 items-start">

                    {/* DATE SIDEBAR - Horizontal on Mobile, Vertical on Desktop */}
                    <div className="lg:col-span-3 bg-white rounded-[2rem] md:rounded-[2.5rem] p-4 md:p-6 shadow-[0_20px_50px_rgba(0,0,0,0.08)] flex lg:flex-col overflow-x-auto lg:overflow-x-visible gap-3 md:gap-4 no-scrollbar">
                        {dates.map((d) => {
                            const isActive = selectedDate === d.dateStr;
                            return (
                                <button
                                    key={d.dateStr}
                                    onClick={() => setSelectedDate(d.dateStr)}
                                    className={`flex-shrink-0 w-40 lg:w-full text-left p-4 lg:p-8 rounded-[1.5rem] lg:rounded-[1.8rem] transition-all duration-300 flex flex-col gap-1 md:gap-1.5 relative border-2 ${isActive
                                        ? 'bg-white border-emerald-500 shadow-xl shadow-emerald-500/10'
                                        : 'bg-transparent border-transparent hover:bg-slate-50'
                                        }`}
                                >
                                    <div className={`font-black text-base lg:text-xl tracking-tight leading-none ${isActive ? 'text-slate-900' : 'text-slate-400'}`}>
                                        {d.display}
                                    </div>
                                    <div className={`text-[8px] lg:text-[10px] font-black uppercase tracking-[0.2em] md:tracking-[0.3em] flex items-center gap-2 ${isActive ? 'text-emerald-500' : 'text-slate-300'}`}>
                                        {d.days === 0 && <Zap size={10} className="fill-emerald-500" />} {d.label}
                                    </div>
                                    {isActive && (
                                        <div className="hidden lg:block absolute right-6 top-1/2 -translate-y-1/2 w-2 h-10 bg-emerald-500 rounded-full shadow-lg shadow-emerald-500/30"></div>
                                    )}
                                </button>
                            );
                        })}
                    </div>

                    {/* SLOT LISTING */}
                    <div className="lg:col-span-9 bg-white rounded-[2rem] md:rounded-[3rem] shadow-[0_30px_100px_rgba(0,0,0,0.1)] border border-slate-100 overflow-hidden min-h-[500px] md:min-h-[600px]">

                        {/* NAVY HEADER */}
                        <div className="bg-[#1e293b] p-6 md:p-12 flex flex-col md:flex-row justify-between items-center text-white relative gap-6 md:gap-8">
                            <div className="space-y-1.5 flex-1 w-full text-center md:text-left">
                                <h2 className="text-xl md:text-2xl font-black uppercase tracking-[0.1em] text-emerald-400 leading-none">Arena Deployment</h2>
