export default PublicHome;

import React, { useEffect, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { bookingsAPI } from '../api/client';
import {
    CheckCircle,
    Clock4,
    RefreshCw,
    Trophy,
    ShieldCheck,
    Hash,
    Zap,
    ArrowRight,
    AlertCircle,
    XCircle,
    User,
    Phone,
    Calendar,
    MapPin
} from 'lucide-react';

const SuccessPage = () => {
    const location = useLocation();
    const navigate = useNavigate();
    const initialBooking = location.state?.booking;
    const [booking, setBooking] = useState(initialBooking);
    const [liveStatus, setLiveStatus] = useState(initialBooking?.bookingStatus || 'pending');
    const [polling, setPolling] = useState(true);

    useEffect(() => {
        if (!initialBooking) {
            navigate('/');
        }
    }, [initialBooking, navigate]);

    // Poll for live status updates every 5 seconds
    useEffect(() => {
        if (!initialBooking?._id) return;

        const pollStatus = async () => {
            try {
                const res = await bookingsAPI.getById(initialBooking._id);
                const updated = res.data.booking || res.data;
                setBooking(updated);
                setLiveStatus(updated.bookingStatus);
                setSlotStatus(updated.slot?.status || 'hold');

                // Stop polling if final state reached
                if (['confirmed', 'rejected'].includes(updated.bookingStatus)) {
                    setPolling(false);
                }
            } catch (err) {
                console.error('Status poll error:', err);
            }
        };

        pollStatus(); // Initial fetch
        const interval = setInterval(pollStatus, 5000);
        return () => clearInterval(interval);
    }, [initialBooking]);

    if (!booking) return null;

    const formatTime12h = (time24) => {
        if (!time24) return '';
        const [hours, minutes] = time24.split(':');
        const h = parseInt(hours);
        const ampm = h >= 12 ? 'PM' : 'AM';
        const h12 = h % 12 || 12;
        return `${h12}:${minutes} ${ampm}`;
    };

    const getStatusConfig = () => {
        switch (liveStatus) {
            case 'confirmed':
                return {
                    icon: <CheckCircle size={48} className="text-emerald-400" />,
                    title: 'Booking Confirmed',
                    subtitle: 'Your slot has been secured successfully',
                    headerBg: 'bg-emerald-900',
                    badgeBg: 'bg-emerald-500/10',
                    badgeBorder: 'border-emerald-500/20',
                    dotColor: 'bg-emerald-500',
                    dotShadow: 'shadow-emerald-500/50',
                    statusText: 'CONFIRMED',
                    statusColor: 'text-emerald-400',
                    slotLabel: 'BOOKED',
                    slotBg: 'bg-emerald-500/10',
                    slotColor: 'text-emerald-600'
                };
            case 'rejected':
                return {
                    icon: <XCircle size={48} className="text-red-400" />,
                    title: 'Booking Rejected',
                    subtitle: 'Your booking could not be processed',
                    headerBg: 'bg-red-900',
                    badgeBg: 'bg-red-500/10',
                    badgeBorder: 'border-red-500/20',
                    dotColor: 'bg-red-500',
                    dotShadow: 'shadow-red-500/50',
                    statusText: 'REJECTED',
                    statusColor: 'text-red-400',
                    slotLabel: 'FREE',
                    slotBg: 'bg-red-50',
                    slotColor: 'text-red-600'
                };
            case 'hold':
                return {
                    icon: <AlertCircle size={48} className="text-blue-400" />,
                    title: 'Booking On Hold',
                    subtitle: 'Under review by admin',
                    headerBg: 'bg-blue-900',
                    badgeBg: 'bg-blue-500/10',
                    badgeBorder: 'border-blue-500/20',
                    dotColor: 'bg-blue-500',
                    dotShadow: 'shadow-blue-500/50',
                    statusText: 'ON HOLD',
                    statusColor: 'text-blue-400',
                    slotLabel: 'HOLD',
                    slotBg: 'bg-blue-50',
                    slotColor: 'text-blue-600'
                };
            default: // pending
                return {
                    icon: <Clock4 size={48} className="text-yellow-400" />,
                    title: 'Booking Pending',
                    subtitle: 'Waiting for confirmation',
                    headerBg: 'bg-[#0F172A]',
                    badgeBg: 'bg-yellow-500/10',
                    badgeBorder: 'border-yellow-500/20',
                    dotColor: 'bg-yellow-500',
                    dotShadow: 'shadow-yellow-500/50',
                    statusText: 'PENDING',
                    statusColor: 'text-yellow-400',
                    slotLabel: 'HOLD',
                    slotBg: 'bg-yellow-50',
                    slotColor: 'text-yellow-600'
                };
        }
    };

    const config = getStatusConfig();
    const slot = booking.slot || {};

    return (
        <div className="min-h-screen bg-[#F8FAFC] flex items-center justify-center py-10 md:py-20 px-4 md:px-6">
            <div className="max-w-xl w-full">
                <div className="bg-white rounded-[2.5rem] md:rounded-[4rem] shadow-2xl shadow-emerald-950/5 border border-gray-100 overflow-hidden relative transition-all hover:shadow-emerald-950/10">

                    {/* Status Header */}
                    <div className={`${config.headerBg} p-10 md:p-16 text-center text-white relative`}>
                        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
                            <div className="absolute top-[-40px] left-[-40px] w-64 h-64 bg-emerald-500 rounded-full blur-[100px]"></div>
                        </div>

                        <div className={`w-20 h-20 md:w-24 md:h-24 ${config.badgeBg} backdrop-blur-xl rounded-2xl md:rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 md:mb-8 border ${config.badgeBorder} shadow-2xl relative z-10`}>
                            {React.cloneElement(config.icon, { size: 40 })}
                        </div>
                        <h1 className="text-3xl md:text-4xl font-black mb-3 tracking-tighter uppercase relative z-10">
                            {config.title}
                        </h1>
                        <div className="flex items-center justify-center gap-2 md:gap-3 opacity-60 relative z-10">
                            <div className="h-[1px] w-5 md:w-6 bg-white/40"></div>
                            <p className="font-black uppercase text-[8px] md:text-[9px] tracking-[0.2em] md:tracking-[0.4em]">{config.subtitle}</p>
                            <div className="h-[1px] w-5 md:w-6 bg-white/40"></div>
